import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { getCandidateApplications, updateCandidateStatus } from "../../api/electionsApi";

function CandidateReview() {
  const { electionId } = useParams();
  const [candidates, setCandidates] = useState([]);

  useEffect(() => {
    getCandidateApplications(electionId)
      .then(res => setCandidates(res.data))
      .catch(err => console.error(err));
  }, [electionId]);

  const updateStatus = (id, status) => {
    updateCandidateStatus(id, status).then(() => {
      setCandidates(prev =>
        prev.map(c =>
          c.id === id ? { ...c, status } : c
        )
      );
    });
  };

  return (
    <div>
      <h2>Nominations Filed</h2>

      {candidates.length === 0 && <p>No applications</p>}

      {candidates.map(c => (
        <div key={c.id} style={{ border: "1px solid #ccc", padding: "10px" }}>
          <p><b>Name:</b> {c.users?.name}</p>
          <p><b>Email:</b> {c.users?.email}</p>
          <p><b>Manifesto:</b> {c.manifesto}</p>
          <p><b>Status:</b> {c.status}</p>

          <button onClick={() => updateStatus(c.id, "ACCEPTED")}>
            Accept
          </button>

          <button onClick={() => updateStatus(c.id, "REJECTED")}>
            Reject
          </button>
        </div>
      ))}
    </div>
  );
}

export default CandidateReview;
